{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-spec-compressor-placeholder-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前候选提案围绕已选中的压缩机进料流量规格缺失、压缩机出口压力控制目标缺失、压缩机最小流量旁路参数缺失，以及产品冷却器出口流缺少下游连接的问题生成；冷却器本体仅作为出口条件可能变化的解释性上下文，不建议直接修改。",
      "issues": [
        {
          "title": "压缩机进料流缺少流量规格",
          "detail": "Recycle Compressor Feed 已给出压力和温度，但诊断指出缺少流量规格，可能阻止进料边界条件完整定义。",
          "severity": "error",
          "target": {
            "type": "stream",
            "id": "feed-91"
          },
          "citations": [
            "diag-2",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "title": "压缩机出口压力控制目标缺失",
          "detail": "Recycle Compressor 配置为 outlet_pressure 控制模式，但诊断指出缺少出口压力目标；当前下游流已有压力值，可作为候选占位来源供用户确认。",
          "severity": "error",
          "target": {
            "type": "unit",
            "id": "compressor-21"
          },
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        },
        {
          "title": "压缩机防喘振复核所需最小流量旁路参数缺失",
          "detail": "Recycle Compressor 标记 anti_surge_review_required 为 true，但缺少 minimum flow bypass percent 参数。",
          "severity": "error",
          "target": {
            "type": "unit",
            "id": "compressor-21"
          },
          "citations": [
            "diag-4",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        },
        {
          "title": "产品冷却器出口流缺少下游消费者或出口汇",
          "detail": "Product Cooler Outlet 91 没有连接到任何 downstream consumer 或 export sink，导致当前快照为 invalid_topology；该拓扑修复风险较高，应仅以待确认连接占位提出。",
          "severity": "error",
          "target": {
            "type": "stream",
            "id": "cooler-outlet-91"
          },
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Recycle Compressor Feed 添加待确认的流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-91"
          },
          "rationale": "该流已被诊断为缺少 flow rate specification；补入占位字段可将问题限定为用户确认具体流量数值和单位，而不改变现有压力、温度或拓扑。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "required": true,
                "value": null,
                "unit": null,
                "reason": "STREAM_SPEC_MISSING: Recycle Compressor Feed is missing flow rate specification."
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-1",
            "snapshot-1"
          ],
          "confidence": 0.86
        },
        {
          "action": "candidate_edit",
          "title": "为 Recycle Compressor 添加出口压力目标候选占位",
          "target": {
            "type": "unit",
            "id": "compressor-21"
          },
          "rationale": "压缩机配置为 outlet_pressure 控制，但目标值缺失；当前压缩机出口流 Compressor Outlet 91 的 pressure_kpa 为 430，可作为待确认的候选目标占位，而不是自动执行参数写入。",
          "patch": {
            "parameter_placeholders": {
              "outlet_pressure_target_kpa": {
                "required": true,
                "candidate_value": 430,
                "unit": "kPa",
                "source": "compressor-outlet-91.specs.pressure_kpa",
                "reason": "COMPRESSOR_OUTLET_PRESSURE_TARGET_MISSING under outlet_pressure control mode."
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ],
          "confidence": 0.8
        },
        {
          "action": "candidate_edit",
          "title": "为 Recycle Compressor 添加最小流量旁路百分比待确认占位",
          "target": {
            "type": "unit",
            "id": "compressor-21"
          },
          "rationale": "anti_surge_review_required 为 true 且诊断指出 minimum flow bypass percent 缺失；由于输入中没有可直接推导的数值，应仅添加必填占位以提示用户确认。",
          "patch": {
            "parameter_placeholders": {
              "minimum_flow_bypass_percent": {
                "required": true,
                "value": null,
                "unit": "percent",
                "reason": "COMPRESSOR_MINIMUM_FLOW_BYPASS_MISSING: anti-surge review requires minimum flow bypass percent."
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-4",
            "flowdoc-unit-1",
            "snapshot-1"
          ],
          "confidence": 0.84
        },
        {
          "action": "candidate_edit",
          "title": "为 Product Cooler Outlet 91 添加下游出口汇连接占位",
          "target": {
            "type": "stream",
            "id": "cooler-outlet-91"
          },
          "rationale": "该流未连接到任何下游消费者或出口汇，且当前求解快照为 invalid_topology；由于请求中没有现成下游单元或出口汇对象证据，建议仅创建待确认的连接占位，避免直接重连或假定具体对象。",
          "patch": {
            "connection_placeholder": {
              "downstream": {
                "required": true,
                "target_type": "export_sink_or_consumer",
                "target_id": null,
                "reason": "STREAM_DISCONNECTED: Product Cooler Outlet 91 is not connected to any downstream consumer or export sink."
              }
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ],
          "confidence": 0.78
        }
      ],
      "notes": [
        {
          "detail": "未对 cooler-21 本体提出编辑；诊断明确指出冷却器出口条件在下游汇恢复后可能变化，因此冷却器自身应保留为解释性上下文。",
          "citations": [
            "diag-5",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        }
      ]
    }
  ]
}
